// Validate callback token and extract payload
const EXPECTED_TOKEN = 'ragm-pipeline-callback-2026';

const req = $input.first().json;
const headers = req.headers || {};
const body = req.body || req;

const token = headers['x-callback-token'] || headers['X-Callback-Token'] || '';
if (EXPECTED_TOKEN && token !== EXPECTED_TOKEN) {
  return [{ json: { ignored: true, reason: 'invalid_token' } }];
}

const pipelineStatus = body.status || 'unknown';
const platform = body.source_platform || null;
const replyInfo = body.platform_reply_info || {};

if (!platform) {
  return [{ json: { ignored: true, reason: 'no_source_platform' } }];
}

return [{
  json: {
    status: pipelineStatus,
    source_platform: platform,
    platform_reply_info: replyInfo,
    project_id: body.project_id || null,
    tenant_id: body.tenant_id || null,
    tenant_slug: body.tenant_slug || null,
    run_id: body.run_id || null,
    download_url: body.download_url || null,
    file_name: body.file_name || 'quotation.docx',
    error_step: body.error_step || null,
    error_message: body.error_message || null,
  }
}];

// Prepare Slack delivery params for the local helper service.
const input = $input.first().json;
const replyInfo = input.platform_reply_info || {};
return [{ json: {
  project_id: input.project_id || null,
  tenant_slug: input.tenant_slug || 'acme',
  channel_id: replyInfo.channel_id || replyInfo.user_id || null,
  bot_token: replyInfo.bot_token || '',
  user_id: replyInfo.user_id || '',
  file_name: input.file_name || 'quotation.docx',
  status: input.status || 'unknown',
  error_step: input.error_step || null,
  error_message: input.error_message || null,
} }];

// The Slack file completion call crashes n8n's Task Runner sandbox.
// Post JSON to a local helper process that runs the same delivery logic outside the sandbox.
const http = require('http');

function postJson(url, payload) {
  return new Promise((resolve, reject) => {
    const body = Buffer.from(JSON.stringify(payload));
    const req = http.request({
      hostname: '127.0.0.1',
      port: 3105,
      path: '/deliver',
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': String(body.length),
      },
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const text = Buffer.concat(chunks).toString();
        let data;
        try { data = JSON.parse(text); } catch (e) { data = { raw: text }; }
        if (res.statusCode >= 400) {
          reject(new Error('Slack helper HTTP ' + res.statusCode + ': ' + text));
          return;
        }
        resolve(data);
      });
    });
    req.on('error', reject);
    req.setTimeout(180000, () => { req.destroy(); reject(new Error('Slack helper timeout')); });
    req.write(body);
    req.end();
  });
}

const result = await postJson('http://127.0.0.1:3105/deliver', $input.first().json);
return [{ json: result }];

// Telegram delivery: login to backend, download DOCX, send via Telegram API
const https = require('https');
const http = require('http');

const BACKEND_API_URL = 'http://172.17.0.1:3001';
const LOGIN_EMAIL = 'admin@acme.com';
const LOGIN_PASSWORD = 'admin123';

function parseUrl(s) {
  const m = s.match(/^(https?):\/\/([^\/:]+)(?::(\d+))?(\/.*)$/);
  if (!m) return { protocol: 'https:', hostname: s, port: null, path: '/' };
  return { protocol: m[1] + ':', hostname: m[2], port: m[3] || null, path: m[4] || '/' };
}

function nativeRequest(method, reqUrl, headers, body) {
  return new Promise((resolve, reject) => {
    const opts = parseUrl(reqUrl);
    const mod = opts.protocol === 'https:' ? https : http;
    const req = mod.request({ hostname: opts.hostname, port: opts.port, path: opts.path, method, headers: headers || {} }, (res) => {
      if (res.statusCode === 301 || res.statusCode === 302) { nativeRequest(method, res.headers.location, headers, body).then(resolve).catch(reject); return; }
      const chunks = []; res.on('data', c => chunks.push(c));
      res.on('end', () => resolve({ statusCode: res.statusCode, body: Buffer.concat(chunks) }));
    });
    req.on('error', reject); req.setTimeout(120000, () => { req.destroy(); reject(new Error('timeout')); });
    if (body) req.write(body); req.end();
  });
}

const input = $input.first().json;
const replyInfo = input.platform_reply_info || {};
const chatId = replyInfo.chat_id;
const BOT_TOKEN = replyInfo.bot_token || '';

if (!chatId || !BOT_TOKEN) {
  return [{ json: { delivered: false, reason: 'missing chat_id or bot_token' } }];
}

if (input.status === 'completed' && input.project_id) {
  const tenantSlug = input.tenant_slug || 'acme';
  const loginRes = await nativeRequest('POST', BACKEND_API_URL + '/api/auth/login',
    { 'Content-Type': 'application/json', 'x-tenant-slug': tenantSlug },
    Buffer.from(JSON.stringify({ email: LOGIN_EMAIL, password: LOGIN_PASSWORD }))
  );
  const token = JSON.parse(loginRes.body.toString()).access_token;
  const dlRes = await nativeRequest('GET',
    BACKEND_API_URL + '/api/projects/' + input.project_id + '/quotation/download-file?format=docx',
    { 'Authorization': 'Bearer ' + token, 'x-tenant-slug': tenantSlug }, null
  );
  if (dlRes.statusCode !== 200) throw new Error('Download failed');
  const fileData = dlRes.body;
  const fname = input.file_name || 'quotation.docx';
  const boundary = '----cbTg' + Date.now();
  const CRLF = '\r\n';
  const parts = [];
  parts.push(Buffer.from('--' + boundary + CRLF + 'Content-Disposition: form-data; name="chat_id"' + CRLF + CRLF + String(chatId) + CRLF));
  parts.push(Buffer.from('--' + boundary + CRLF + 'Content-Disposition: form-data; name="caption"' + CRLF + CRLF + 'Your quotation is ready!' + CRLF));
  parts.push(Buffer.from('--' + boundary + CRLF + 'Content-Disposition: form-data; name="document"; filename="' + fname + '"' + CRLF + 'Content-Type: application/vnd.openxmlformats-officedocument.wordprocessingml.document' + CRLF + CRLF));
  parts.push(fileData);
  parts.push(Buffer.from(CRLF + '--' + boundary + '--' + CRLF));
  const body = Buffer.concat(parts);
  await nativeRequest('POST', 'https://api.telegram.org/bot' + BOT_TOKEN + '/sendDocument',
    { 'Content-Type': 'multipart/form-data; boundary=' + boundary, 'Content-Length': String(body.length) }, body
  );
} else if (input.status === 'failed') {
  await nativeRequest('POST', 'https://api.telegram.org/bot' + BOT_TOKEN + '/sendMessage',
    { 'Content-Type': 'application/json' },
    Buffer.from(JSON.stringify({ chat_id: chatId, text: 'Quotation failed. Step: ' + (input.error_step || '?') + ' Error: ' + (input.error_message || '?') }))
  );
}

return [{ json: { delivered: true, platform: 'telegram' } }];

// WhatsApp delivery via WAHA API (text with download link)
